// src/components/ImpressaoListaAgendamentos.js
import React, { useEffect } from 'react';

export default function ImpressaoListaAgendamentos(props) {
  useEffect(() => {
    setTimeout(() => window.print(), 200);
  }, []);

  return (
    <div className="print:bg-white p-8" style={{ background: "#fff" }}>
      {/* Topo: Disciplina, Semestre, Data */}
      <div className="mb-6">
        <h2 className="text-2xl font-bold mb-2">Lista de Agendamentos</h2>
        <div className="text-lg">
          <div><strong>Disciplina:</strong> {disciplina}</div>
          <div><strong>Semestre:</strong> {semestre}</div>
          <div><strong>Data:</strong> {data}</div>
        </div>
      </div>
      {/* Grid */}
      <table className="w-full border border-gray-300">
        <thead>
          <tr>
            <th className="border px-3 py-2 text-left">N°</th>
            <th className="border px-3 py-2 text-left">Operador</th>
            <th className="border px-3 py-2 text-left">Auxiliar</th>
            <th className="border px-3 py-2 text-left">Paciente</th>
            <th className="border px-3 py-2 text-left">Telefone</th>
            <th className="border px-3 py-2 text-left">Status</th>
          </tr>
        </thead>
        <tbody>
          {agendamentos.map((ag, idx) => (
            <tr key={ag.id || idx}>
              <td className="border px-3 py-2">{idx + 1}</td>
              <td className="border px-3 py-2">{ag.operadorNome}</td>
              <td className="border px-3 py-2">{ag.auxiliarNome}</td>
              <td className="border px-3 py-2">{ag.pacienteNome}</td>
              <td className="border px-3 py-2">{ag.telefone}</td>
              <td className="border px-3 py-2">{ag.status}</td>
            </tr>
          ))}
        </tbody>
      </table>
      {/* Só imprime a tabela, sem sidebar/menu */}
      <style>{`@media print { body * { visibility: hidden; } .print\\:bg-white, .print\\:bg-white * { visibility: visible !important; } .print\\:bg-white { position: absolute; left: 0; top: 0; width: 100vw; } }`}</style>
    </div>
  );
}
